-- ----------------------------
-- Table structure for medical_record
-- ----------------------------
DROP TABLE IF EXISTS `medical_record`;
CREATE TABLE `medical_record`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'и®°еҪ•ID',
  `record_no` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'и®°еҪ•зј–еҸ·',
  `patient_id` bigint(20) NOT NULL COMMENT 'жӮЈиҖ…ID',
  `doctor_id` bigint(20) NOT NULL COMMENT 'еҢ»з”ҹID',
  `appointment_id` bigint(20) NULL DEFAULT NULL COMMENT 'йў„зәҰID',
  `diagnosis` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'иҜҠж–ӯз»“жһң',
  `treatment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'жІ»з–—ж–№жЎҲ',
  `record_date` date NOT NULL COMMENT 'е°ұиҜҠж—Ҙжңҹ',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'еҢ»з”ҹеӨҮжіЁ',
  `follow_up` date NULL DEFAULT NULL COMMENT 'йҡҸи®ҝж—Ҙжңҹ',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_record_no`(`record_no` ASC) USING BTREE,
  INDEX `idx_patient_id`(`patient_id` ASC) USING BTREE,
  INDEX `idx_doctor_id`(`doctor_id` ASC) USING BTREE,
  INDEX `idx_appointment_id`(`appointment_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'е°ұиҜҠи®°еҪ•иЎЁ' ROW_FORMAT = DYNAMIC;

