-- ----------------------------
-- Table structure for medicine
-- ----------------------------
DROP TABLE IF EXISTS `medicine`;
CREATE TABLE `medicine`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'иҚҜе“ҒID',
  `medicine_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'иҚҜе“Ғзј–з Ғ',
  `medicine_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'иҚҜе“ҒеҗҚз§°',
  `specification` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'и§„ж ј',
  `dosage_form` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еүӮеһӢ(зүҮеүӮ/иғ¶еӣҠ/жіЁе°„еүӮзӯү)',
  `manufacturer` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'з”ҹдә§еҺӮе®¶',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'зұ»еҲ«(еӨ„ж–№иҚҜ/йқһеӨ„ж–№иҚҜ)',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT 'еҚ•д»·',
  `stock` int(11) NULL DEFAULT 0 COMMENT 'еә“еӯҳйҮҸ',
  `instructions` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'дҪҝз”ЁиҜҙжҳҺ',
  `status` tinyint(4) NULL DEFAULT 1 COMMENT 'зҠ¶жҖҒ(0:дёӢжһ¶,1:дёҠжһ¶)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  `category_id` int(11) NULL DEFAULT NULL COMMENT 'еҲҶзұ»id',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_medicine_code`(`medicine_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 57 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'иҚҜе“ҒиЎЁ' ROW_FORMAT = DYNAMIC;

