-- ----------------------------
-- Table structure for medicine_category
-- ----------------------------
DROP TABLE IF EXISTS `medicine_category`;
CREATE TABLE `medicine_category`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT 'еҲҶзұ»ID',
  `category_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'еҲҶзұ»еҗҚз§°',
  `category_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'еҲҶзұ»зј–з Ғ',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'еҲҶзұ»жҸҸиҝ°',
  `status` tinyint(4) NULL DEFAULT 1 COMMENT 'зҠ¶жҖҒ(0:зҰҒз”Ё,1:еҗҜз”Ё)',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'еҲӣе»әж—¶й—ҙ',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'жӣҙж–°ж—¶й—ҙ',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_category_code`(`category_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'иҚҜе“ҒеҲҶзұ»иЎЁ' ROW_FORMAT = DYNAMIC;

-- ----------------------------
