INSERT INTO `supplier` VALUES (2, 'SUP-002', 'еӣҪиҚҜеҷЁжў°пјҲеҚҺеҢ—пјүй…ҚйҖҒдёӯеҝғ', 'жқҺеЁң', '13800000002', 'еҢ—дә¬еёӮеӨ§е…ҙеҢәеҢ»иҚҜеӣӯеҢә66еҸ·', 'gyqx-north@demo.com', 1, '2026-04-07 14:50:00', '2026-04-07 14:50:00');
