-- medicine ж”№йҖ пјҡеҲ¶йҖ е•Ҷдҝқз•ҷе…је®№пјҢж–°еўһ supplier_id дҪңдёәйҮҮиҙӯдё»е…іиҒ”
ALTER TABLE `medicine` ADD COLUMN `supplier_id` bigint(20) NULL DEFAULT NULL COMMENT 'дҫӣеә”е•ҶID' AFTER `manufacturer`;
ALTER TABLE `medicine` ADD INDEX `idx_medicine_supplier_id`(`supplier_id` ASC);
-- еўһеҠ дҫӣеә”е•Ҷж•°жҚ®пјҡжҠҠиҚҜе“ҒеҲ¶йҖ е•ҶиЎҘе……дёәеҸҜйҖүдҫӣеә”е•ҶпјҲеҺ»йҮҚпјү
INSERT INTO `supplier` (`supplier_code`, `name`, `contact_name`, `contact_phone`, `address`, `email`, `status`, `create_time`, `update_time`)
SELECT
  CONCAT('SUP-AUTO-', LPAD(ROW_NUMBER() OVER (ORDER BY t.manufacturer), 3, '0')),
  t.manufacturer,
  'зі»з»ҹеҲқе§ӢеҢ–',
  '13800000000',
  'еҫ…з»ҙжҠӨ',
  NULL,
  1,
  '2026-04-07 15:00:00',
  '2026-04-07 15:00:00'
FROM (
  SELECT DISTINCT `manufacturer`
  FROM `medicine`
  WHERE `manufacturer` IS NOT NULL AND `manufacturer` <> ''
) t
LEFT JOIN `supplier` s ON s.`name` = t.`manufacturer`
WHERE s.`id` IS NULL;

-- еӣһеЎ«жүҖжңүиҚҜе“Ғдҫӣеә”е•ҶпјҢдёҚе…Ғи®ё NULL
UPDATE `medicine` m
JOIN `supplier` s ON s.`name` = m.`manufacturer`
SET m.`supplier_id` = s.`id`
WHERE m.`supplier_id` IS NULL;

-- е…ңеә•пјҡеҰӮжһңиҝҳжңүз©әеҖјпјҢз»ҹдёҖеҪ’еұһеҲ°дҫӣеә”е•ҶID=1
UPDATE `medicine` SET `supplier_id` = 1 WHERE `supplier_id` IS NULL;

-- ејәеҲ¶йқһз©ә + еӨ–й”®зәҰжқҹ
ALTER TABLE `medicine` MODIFY COLUMN `supplier_id` bigint(20) NOT NULL COMMENT 'дҫӣеә”е•ҶID';
ALTER TABLE `medicine` ADD CONSTRAINT `fk_medicine_supplier` FOREIGN KEY (`supplier_id`) REFERENCES `supplier` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT;

